"use strict";(globalThis.webpackChunkdoqumentation=globalThis.webpackChunkdoqumentation||[]).push([[9138],{58095(e,n,i){i.r(n),i.d(n,{assets:()=>h,contentTitle:()=>a,default:()=>l,frontMatter:()=>u,metadata:()=>r,toc:()=>d});const r=JSON.parse('{"id":"learning/courses/quantum-computing-in-practice/introduction","title":"Einleitung","description":"Ein kostenloser IBM-Kurs \xfcber Quantencomputing im Utility-Ma\xdfstab mit realistischen Anwendungsf\xe4llen und Best Practices","source":"@site/i18n/de/docusaurus-plugin-content-docs/current/learning/courses/quantum-computing-in-practice/introduction.mdx","sourceDirName":"learning/courses/quantum-computing-in-practice","slug":"/learning/courses/quantum-computing-in-practice/introduction","permalink":"/learning/courses/quantum-computing-in-practice/introduction","draft":false,"unlisted":false,"editUrl":"https://github.com/JanLahmann/doQumentation/tree/main/docs/learning/courses/quantum-computing-in-practice/introduction.mdx","tags":[],"version":"current","frontMatter":{"title":"Einleitung","sidebar_label":"Einleitung","description":"Ein kostenloser IBM-Kurs \xfcber Quantencomputing im Utility-Ma\xdfstab mit realistischen Anwendungsf\xe4llen und Best Practices","notebook_path":"learning/courses/quantum-computing-in-practice/introduction.ipynb"},"sidebar":"tutorialsSidebar","previous":{"title":"\xdcbersicht","permalink":"/learning/courses/quantum-computing-in-practice/"},"next":{"title":"Quantencircuits ausf\xfchren","permalink":"/learning/courses/quantum-computing-in-practice/running-quantum-circuits"}}');var t=i(74848),s=i(28453);const u={title:"Einleitung",sidebar_label:"Einleitung",description:"Ein kostenloser IBM-Kurs \xfcber Quantencomputing im Utility-Ma\xdfstab mit realistischen Anwendungsf\xe4llen und Best Practices",notebook_path:"learning/courses/quantum-computing-in-practice/introduction.ipynb"},a="Kurseinleitung {#course-introduction}",h={},d=[{value:"\xdcber diesen Kurs",id:"about-this-course",level:2},{value:"Quantum Utility",id:"quantum-utility",level:3},{value:"Natursimulation",id:"simulating-nature",level:3},{value:"Fokus auf gr\xf6\xdfere Quantenprozessoren",id:"a-focus-on-larger-quantum-processors",level:3},{value:"Zielgruppe und Kursziele",id:"audience-and-course-goals",level:3},{value:"Die Geschichte der Berechnung",id:"the-story-of-computation",level:2},{value:"Rechenger\xe4te seit der Antike",id:"computing-devices-since-ancient-times",level:3},{value:"Verbindungen zur physischen Welt",id:"connections-to-the-physical-world",level:3},{value:"Mooresches Gesetz",id:"moores-law",level:3},{value:"Quantencomputing",id:"quantum-computing",level:2},{value:"Quantenmechanik und Berechnung",id:"quantum-mechanics-and-computation",level:3},{value:"Quantencomputing in der Theorie",id:"quantum-computing-in-theory",level:3},{value:"Quantencomputing in der Praxis",id:"quantum-computing-in-practice",level:3},{value:"Potenzielle Anwendungen",id:"potential-applications",level:3},{value:"Stand der Technik",id:"state-of-the-technology",level:3},{value:"Fazit",id:"conclusion",level:2}];function c(e){const n={a:"a",em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",li:"li",p:"p",strong:"strong",ul:"ul",...(0,s.R)(),...e.components},{IBMVideo:i}=n;return i||function(e,n){throw new Error("Expected "+(n?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("IBMVideo",!0),(0,t.jsxs)(t.Fragment,{children:["\n",(0,t.jsx)(n.header,{children:(0,t.jsx)(n.h1,{id:"course-introduction",children:"Kurseinleitung"})}),"\n",(0,t.jsxs)(n.p,{children:["Bitte f\xfclle vor dem Beginn diese kurze ",(0,t.jsx)(n.a,{href:"https://your.feedback.ibm.com/jfe/form/SV_6PadhMQiGWsxXTM",children:"Vorabbefragung"})," aus, die wichtig ist, um unser Kursangebot und die Nutzererfahrung zu verbessern."]}),"\n",(0,t.jsxs)(n.p,{children:["Klicke unten, um eine Kurseinleitung von Olivia Lanes anzuh\xf6ren, oder \xf6ffne das Video in einem separaten Fenster auf ",(0,t.jsx)(n.a,{href:"https://youtube.com/watch?v=sVRpKhCfKRI",children:"YouTube."})]}),"\n",(0,t.jsx)(i,{id:"134063425",title:"In diesem Video gibt Olivia Lanes einen \xdcberblick \xfcber das praktische Quantencomputing in der Utility-\xc4ra. Sie behandelt die Zielgruppe und einige Hintergr\xfcnde zu Themen wie dem Mooreschen Gesetz und den theoretischen Grundlagen des Quantencomputings."}),"\n",(0,t.jsx)(n.h2,{id:"about-this-course",children:"\xdcber diesen Kurs"}),"\n",(0,t.jsxs)(n.p,{children:["Willkommen bei ",(0,t.jsx)(n.em,{children:"Quantum Computing in Practice"})," \u2013 einem Kurs, der sich auf die Quantencomputer von heute und ihre volle Nutzung konzentriert.\nEr behandelt realistische potenzielle Anwendungsf\xe4lle des Quantencomputings sowie Best Practices f\xfcr den Betrieb von und das Experimentieren mit Quantenprozessoren mit 100 oder mehr Qubits."]}),"\n",(0,t.jsx)(n.h3,{id:"quantum-utility",children:"Quantum Utility"}),"\n",(0,t.jsxs)(n.p,{children:["Es ist eine aufregende Zeit f\xfcr das Quantencomputing.\nNach vielen Jahren theoretischer und experimenteller Forschung und Entwicklung n\xe4hern sich Quantencomputer einem Punkt, an dem sie anfangen k\xf6nnen, mit klassischen Computern zu konkurrieren und ",(0,t.jsx)(n.em,{children:"Utility"})," zu demonstrieren."]}),"\n",(0,t.jsxs)(n.p,{children:["Utility ist nicht dasselbe wie ",(0,t.jsx)(n.em,{children:"Quantum Advantage"}),", was sich darauf bezieht, dass Quantencomputer klassische Computer bei bedeutungsvollen Aufgaben ",(0,t.jsx)(n.em,{children:"\xfcbertreffen"}),".\nKlassische Computer haben unglaubliche Leistung und Anpassungsf\xe4higkeit, und die Tatsache ist, dass Quantencomputer sie noch nicht schlagen k\xf6nnen.\nWir haben Jahrzehnte der Fortschritte im klassischen Computing erlebt \u2013 nicht nur in der Computing-Hardware, sondern auch in Algorithmen f\xfcr klassische Computer \u2013 und wir k\xf6nnen klar erkennen, dass die Technologie des elektronischen digitalen Computings unsere Welt tiefgreifend ver\xe4ndert hat."]}),"\n",(0,t.jsxs)(n.p,{children:["Quantencomputing hingegen befindet sich in einer anderen Entwicklungsphase.\nQuantencomputing stellt extreme Anforderungen an unsere Kontrolle quantenmechanischer Systeme und treibt die Grenzen der heutigen Technologie voran \u2013 und wir k\xf6nnen nicht realistisch erwarten, diese neue Technologie zu meistern und das klassische Computing direkt vom Start weg zu \xfcbertreffen.\nAber wir sehen Anzeichen, die darauf hindeuten, dass Quantencomputer beginnen, mit klassischen Computermethoden f\xfcr ausgew\xe4hlte Aufgaben wettbewerbsf\xe4hig zu werden, was ein nat\xfcrlicher Schritt in der technologischen Entwicklung des Quantencomputings ist, bekannt als ",(0,t.jsx)(n.em,{children:"Quantum Utility"}),"."]}),"\n",(0,t.jsx)(n.p,{children:"Wenn die Technologie voranschreitet und neue Methoden f\xfcr das Quantencomputing entwickelt werden, k\xf6nnen wir vern\xfcnftigerweise erwarten, dass seine Vorteile zunehmend ausgepr\xe4gter werden \u2013 aber das wird Zeit brauchen.\nWenn das passiert, werden wir wahrscheinlich eine Wechselwirkung mit dem klassischen Computing sehen:\nQuantencomputing-Demonstrationen werden durchgef\xfchrt und das klassische Computing wird reagieren, Quantencomputing wird einen weiteren Schritt machen, und das Muster wird sich wiederholen.\nUnd eines Tages, wenn die Leistung eines Quantencomputers nicht mehr klassisch erreicht werden kann, werden wir vermuten, dass wir einen Quantum Advantage gesehen haben \u2013 aber selbst dann werden wir es nicht mit Sicherheit wissen!\nUnm\xf6glichkeitsnachweise f\xfcr klassische Computer zu erbringen ist, soweit wir wissen, selbst ein unm\xf6glich schwieriges Problem."}),"\n",(0,t.jsx)(n.h3,{id:"simulating-nature",children:"Natursimulation"}),"\n",(0,t.jsx)(n.p,{children:"Klassische Simulatoren \u2013 also Computerprogramme auf klassischen Computern, die physikalische Systeme simulieren \u2013 k\xf6nnen Vorhersagen \xfcber quantenmechanische Systeme machen.\nAber klassische Simulatoren sind nicht quantenmechanisch und k\xf6nnen quantenmechanische Systeme nicht direkt emulieren.\nStattdessen verwenden sie mathematische Berechnungen, um quantenmechanisches Verhalten zu approximieren.\nWenn die Gr\xf6\xdfe der simulierten Systeme w\xe4chst, steigt der daf\xfcr erforderliche Aufwand drastisch an, was Grenzen daf\xfcr setzt, welche Quantensysteme klassisch simuliert werden k\xf6nnen, wie lange die Simulationen dauern und wie genau die Ergebnisse sind."}),"\n",(0,t.jsx)(n.p,{children:"Quantencomputer hingegen k\xf6nnen Quantensysteme direkter emulieren \u2013 und infolgedessen skaliert der von ihnen ben\xf6tigte Aufwand erheblich besser, wenn die Systemgr\xf6\xdfe w\xe4chst.\nDies war tats\xe4chlich Richard Feynmans Idee in den 1980er Jahren, die zum ersten Mal eine Untersuchung des Potenzials von Quantencomputern motivierte.\nMehr dazu werden wir sp\xe4ter sagen!"}),"\n",(0,t.jsx)(n.p,{children:"IBM\xae-Forscher ver\xf6ffentlichten 2023 ein Paper, das zum ersten Mal zeigte, dass ein Quantencomputer mit modernsten klassischen Techniken zur Simulation eines bestimmten physikalischen Modells mithalten kann.\nSeine Ergebnisse k\xf6nnen immer noch durch fortgeschrittene Techniken auf klassischen Computern erreicht werden \u2013 aber er \xfcbertraf Brute-Force-Algorithmen,\nund er bietet auch einen neuen Datenpunkt, mit dem verschiedene Simulationsmethoden (die nicht exakt sind und nicht in ihren Vorhersagen \xfcbereinstimmen) verglichen werden k\xf6nnen."}),"\n",(0,t.jsx)(n.h3,{id:"a-focus-on-larger-quantum-processors",children:"Fokus auf gr\xf6\xdfere Quantenprozessoren"}),"\n",(0,t.jsx)(n.p,{children:"Fr\xfchere Nutzer von IBM-Quantenhardware haben m\xf6glicherweise bemerkt, dass die kleineren Prozessoren, die wir zuvor der \xd6ffentlichkeit zur Verf\xfcgung gestellt haben, offline genommen wurden, um Platz f\xfcr gr\xf6\xdfere Prozessoren (mit 100+ Qubits) zu machen.\nDiese kleineren Prozessoren konnten leicht klassisch simuliert werden.\nObwohl sie \xf6ffentlich zug\xe4ngliche Zwischenschritte in einer fortschreitenden Technologie darstellten, konnten sie unm\xf6glich Quantum Utility demonstrieren: Alles, was mit ihnen getan werden konnte, h\xe4tte genauso leicht mit einer klassischen Simulation durchgef\xfchrt werden k\xf6nnen."}),"\n",(0,t.jsxs)(n.p,{children:["Bei etwa 100 Qubits ist das jedoch nicht mehr der Fall; Quantenprozessoren dieser Gr\xf6\xdfe k\xf6nnen nicht mehr klassisch simuliert werden.\nDas stellt eine Art Phasen\xfcbergang dar \u2013 in eine neue \xc4ra der Quantencomputing-Technologie, in der das ",(0,t.jsx)(n.em,{children:"Potenzial"})," f\xfcr das \xdcbertreffen klassischer Berechnungen existiert.\nHier hat IBM beschlossen, sich zu konzentrieren \u2013 um Quantenrechnerleistung zu suchen und auf einen eventuellen Quantum Advantage hinzuarbeiten."]}),"\n",(0,t.jsx)(n.p,{children:"Wir ermutigen unsere Nutzer, diese neuen Ger\xe4te voll auszunutzen, mit ihnen zu experimentieren, ihre Grenzen zu testen und aus den Erfahrungen f\xfcr die n\xe4chste Generation von Quantenprozessoren, die derzeit in Entwicklung ist, zu lernen.\nDieser Kurs soll dir erm\xf6glichen, das zu tun!"}),"\n",(0,t.jsx)(n.h3,{id:"audience-and-course-goals",children:"Zielgruppe und Kursziele"}),"\n",(0,t.jsx)(n.p,{children:"Dieser Kurs richtet sich an alle, die neue Anwendungen f\xfcr Quantencomputer entwickeln, ihre aktuelle Arbeit im Quantencomputing skalieren oder lernen m\xf6chten, Quantenprozessoren in ihren Workflow einzubinden.\nDazu geh\xf6ren nicht nur Physiker und Informatiker, sondern auch Ingenieure, Chemiker, Materialwissenschaftler und alle anderen mit einem Interesse daran, Quantencomputing-Hardware zu meistern."}),"\n",(0,t.jsx)(n.p,{children:"Der Kurs wird praxisorientiert sein und sich auf den praktischen Einsatz von Quantencomputern konzentrieren.\nFolgende Themen und F\xe4higkeiten werden unter anderem behandelt:"}),"\n",(0,t.jsxs)(n.ul,{children:["\n",(0,t.jsx)(n.li,{children:"Ausf\xfchren von Jobs im Utility-Ma\xdfstab auf Quantenprozessoren \xfcber Qiskit Runtime"}),"\n",(0,t.jsx)(n.li,{children:"Verwendung von Error-Mitigation-Techniken zur Verbesserung der Hardware-Ergebnisse"}),"\n",(0,t.jsx)(n.li,{children:"Potenzielle Anwendungsbereiche f\xfcr nahzeitige Quantencomputer"}),"\n"]}),"\n",(0,t.jsxs)(n.p,{children:["Dieser Kurs behandelt nicht die einf\xfchrende Theorie des Quantencomputings und setzt grundlegende Kenntnisse \xfcber Qubits und Quantum Circuits voraus.\nDer Kurs ",(0,t.jsx)(n.em,{children:"Basics of Quantum Information"})," auf dieser Plattform behandelt dieses Material und wird f\xfcr Quantencomputing-Einsteiger empfohlen."]}),"\n",(0,t.jsx)(n.h2,{id:"the-story-of-computation",children:"Die Geschichte der Berechnung"}),"\n",(0,t.jsxs)(n.p,{children:["Quantencomputing ist eine aufregende neue Technologie in einem fr\xfchen Entwicklungsstadium \u2013 aber es ist nur ein Kapitel in einer Geschichte, die Tausende von Jahren zur\xfcckreicht.\nEs ist die Geschichte der ",(0,t.jsx)(n.em,{children:"Berechnung"})," und ihrer vielschichtigen Verbindungen zur ",(0,t.jsx)(n.em,{children:"physischen Welt"}),"."]}),"\n",(0,t.jsx)(n.h3,{id:"computing-devices-since-ancient-times",children:"Rechenger\xe4te seit der Antike"}),"\n",(0,t.jsxs)(n.p,{children:["Seit der Antike mussten wir Menschen ",(0,t.jsx)(n.em,{children:"Berechnungen"})," durchf\xfchren \u2013 oder, mit anderen Worten, Informationen nach bestimmten Regeln und Einschr\xe4nkungen verarbeiten \u2013, um Kommunikation, Konstruktion, Handel, Wissenschaft und andere Aspekte unseres Lebens zu erm\xf6glichen.\nWir haben uns der physischen Welt um Hilfe zugewandt und durch geniale Entdeckungen Ger\xe4te gebaut, die uns beim Rechnen helfen."]}),"\n",(0,t.jsxs)(n.p,{children:["Vor langer Zeit speicherten Ger\xe4te aus Holz, Knochen und Knoten\xf6sen Informationen und erleichterten Berechnungen.\nMechanische Ger\xe4te, die aus Hebeln, Zahnr\xe4dern und anderen Maschinen gebaut wurden, entwickelten sich von fr\xfchen astronomischen Uhren zu Taschenrechnern bis hin zu ausgefeilten Rechenger\xe4ten wie Differentialanalysatoren, die Gleichungen mithilfe von R\xe4dern und rotierenden Scheiben l\xf6sten.\nSelbst die Technologie des Schreibens hat in dieser Geschichte eine wichtige Rolle gespielt, indem sie ",(0,t.jsx)(n.em,{children:"Menschen"})," erm\xf6glichte, Berechnungen durchzuf\xfchren, zu denen sie sonst nicht in der Lage w\xe4ren."]}),"\n",(0,t.jsx)(n.p,{children:"Wenn wir heute an Computer denken, denken wir tendenziell an elektronische digitale Computer.\nAber das ist eigentlich eine ziemlich neuere Technologie: Elektronische digitale Computer wurden erstmals in den 1940er Jahren gebaut.\n(Im Gegensatz dazu wird angenommen, dass der sumerische Abakus irgendwann zwischen 2700 und 2300 v. Chr. erfunden wurde.)\nDie Technologie hat sich seitdem dramatisch weiterentwickelt und Computer sind nun allgegenw\xe4rtig.\nSie befinden sich in H\xe4usern, Arbeitspl\xe4tzen und in den Fahrzeugen, die uns dazwischen transportieren, und viele von uns tragen sie \xfcberall mit hin."}),"\n",(0,t.jsxs)(n.p,{children:["Wir haben auch ",(0,t.jsx)(n.em,{children:"Supercomputer"}),", die gro\xdfe Sammlungen leistungsstarker klassischer Prozessoren sind, die parallel zusammengeschaltet sind.\nSie geh\xf6ren zu den besten Werkzeugen, die die Menschheit je zur L\xf6sung schwieriger Probleme gebaut hat, und ihre Leistung und Zuverl\xe4ssigkeit schreitet weiterhin voran.\nAber dennoch gibt es wichtige Rechenprobleme, die selbst diese Giganten aufgrund der inh\xe4renten Rechenschwierigkeit dieser Probleme nie l\xf6sen k\xf6nnen."]}),"\n",(0,t.jsx)(n.h3,{id:"connections-to-the-physical-world",children:"Verbindungen zur physischen Welt"}),"\n",(0,t.jsxs)(n.p,{children:["Computer haben viele Verwendungszwecke.\nEine wichtige Verwendung f\xfcr Computer ist das ",(0,t.jsx)(n.em,{children:"Lernen"})," \xfcber die physische Welt und ein besseres Verst\xe4ndnis ihrer Muster.\nHistorische Verwendungen in dieser Kategorie umfassten die Vorhersage von Sonnen- und Mondfinsternissen und Gezeiten, das Verst\xe4ndnis der Bewegung astronomischer K\xf6rper und (in etwas neuerer Zeit) die Modellierung von Explosionen.\nHeute gibt es kaum ein Physiklabor auf der Welt ohne Computer."]}),"\n",(0,t.jsxs)(n.p,{children:["Allgemeiner gesagt waren Physik und Berechnung schon immer miteinander verflochten.\nBerechnung kann nicht im Vakuum existieren: Informationen erfordern ein Medium, und zum Rechnen m\xfcssen wir die physische Welt in irgendeiner Weise nutzen.\nRolf Landauer, ein Informatiker (und IBM-Mitarbeiter), erkannte vor Jahrzehnten, dass Information physisch ist und nur durch eine physische Darstellung existiert.\nDas ",(0,t.jsx)(n.em,{children:"Landauer-Prinzip"})," stellt eine Verbindung zwischen Information und den Gesetzen der Thermodynamik her, aber tats\xe4chlich gibt es viele Verbindungen."]}),"\n",(0,t.jsx)(n.p,{children:"Das Verst\xe4ndnis der physischen Welt ist das Ziel der Physik als Disziplin, aber tats\xe4chlich ist es eine Zweibahnstra\xdfe.\nDurch unser Verst\xe4ndnis der physischen Welt k\xf6nnen wir neue Technologien nutzen, die uns beim Rechnen helfen, und durch sie lernen wir weiterhin \xfcber die physische Welt \u2013 wir ziehen Physik und Computertechnologie quasi am Schopfe hoch."}),"\n",(0,t.jsx)(n.h3,{id:"moores-law",children:"Mooresches Gesetz"}),"\n",(0,t.jsx)(n.p,{children:"Das Mooresche Gesetz ist die Beobachtung, dass sich die maximale Anzahl von Transistoren in einem integrierten Schaltkreis ungef\xe4hr alle 2 Jahre verdoppelt.\nIn den letzten 5 Jahrzehnten haben wir nicht nur diesen Trend beobachtet, sondern auch seine Fr\xfcchte geerntet.\nMit mehr Transistoren auf einem Chip k\xf6nnen wir komplexere Berechnungen durchf\xfchren und das schneller.\nDas ist der Grund, warum Computer im Laufe der Zeit immer leistungsf\xe4higer geworden sind."}),"\n",(0,t.jsx)(n.p,{children:'Das Mooresche \u201eGesetz" neigt sich jedoch zwangsl\xe4ufig seinem Ende.\nExperten sind uneinig dar\xfcber, wann das passieren wird, und einige argumentieren, dass es bereits geschehen ist.\nAber wir wissen mit Sicherheit, dass es unweigerlich enden muss, weil es eine theoretische Grenze f\xfcr die Miniaturisierung von Rechenkomponenten gibt.\nWir k\xf6nnen einen Transistor nicht kleiner als ein Atom machen!\nObwohl das \xfcbertrieben klingen mag, ist das die Wand, auf die wir zusteuern.'}),"\n",(0,t.jsx)(n.p,{children:'Die L\xf6sung ist nicht, aufzugeben und zu sagen: \u201eNun, das ist so gut wie es geht."\nDas widerspricht der menschlichen Natur.\nStattdessen m\xfcssen wir die physische Welt nach neuen Rechenwerkzeugen absuchen, und hier kommt Quantencomputing ins Spiel.'}),"\n",(0,t.jsx)(n.h2,{id:"quantum-computing",children:"Quantencomputing"}),"\n",(0,t.jsx)(n.h3,{id:"quantum-mechanics-and-computation",children:"Quantenmechanik und Berechnung"}),"\n",(0,t.jsx)(n.p,{children:"Die Quantenmechanik wurde Anfang des 20. Jahrhunderts entdeckt und hat bereits eine wichtige Rolle in der Berechnung gespielt.\nTats\xe4chlich hat unser Verst\xe4ndnis der Quantenmechanik die modernen Computer zum Teil erst m\xf6glich gemacht.\nOhne Quantenmechanik w\xe4re es zum Beispiel schwer vorstellbar, dass die Solid-State-Festplatte erfunden worden w\xe4re."}),"\n",(0,t.jsx)(n.h3,{id:"quantum-computing-in-theory",children:"Quantencomputing in der Theorie"}),"\n",(0,t.jsx)(n.p,{children:"Als Richard Feynman 1982 zum ersten Mal das Konzept eines Quantencomputers vorschlug, konzentrierte er sich auf die Simulation quantenmechanischer Systeme.\nDie daf\xfcr erforderlichen Berechnungen schienen f\xfcr gew\xf6hnliche Computer zu schwierig zu sein \u2013 aber vielleicht k\xf6nnten die Systeme mit einem Computer, der nach einer quantenmechanischen Beschreibung der Welt arbeitet, direkt emuliert werden."}),"\n",(0,t.jsx)(n.p,{children:"Heute ist das einer der vielversprechendsten Wege f\xfcr das Quantencomputing.\nNach unserem besten Verst\xe4ndnis ist die Natur nicht klassisch \u2013 sie ist quantenmechanisch.\nDaher k\xf6nnten Quantencomputer wertvolle Werkzeuge sein, um sie zu verstehen.\nKlassische Computer hingegen k\xf6nnen nur approximieren, was in der Natur tats\xe4chlich geschieht, und in einigen F\xe4llen sind diese Approximationen sehr begrenzt."}),"\n",(0,t.jsx)(n.p,{children:"Eine M\xf6glichkeit, dar\xfcber nachzudenken, ist durch eine Analogie zu Windkan\xe4len.\nStr\xf6mungsdynamik ist bekannterma\xdfen schwer mathematisch zu simulieren und vorherzusagen.\nEs ist zum Beispiel zu kostspielig und unpraktisch, ein Auto im Gegenwind zu simulieren, daher bauen Automobilhersteller tats\xe4chlich Tunnel mit blasendem Wind und fahren Autos durch sie hindurch, um ihre Leistung zu testen.\nDas hei\xdft, sie erzeugen Wind anstatt ihn zu simulieren.\nDen Bau eines Quantencomputers zur Untersuchung der physischen Welt kann man in gewisser Weise damit vergleichen, einen Windkanal zur Untersuchung von Wind auf Autos zu bauen.\nQuantencomputer k\xf6nnen die Naturgesetze auf molekularer Ebene direkt emulieren, da sie in \xdcbereinstimmung mit diesen Gesetzen handeln \u2013\ndas bedeutet, sie emulieren die Natur anstatt sie durch Formeln und Berechnungen zu simulieren."}),"\n",(0,t.jsxs)(n.p,{children:["Andere folgten Feynmans Ideen \u2013 und verkn\xfcpften diese Ideen mit einer Theorie der ",(0,t.jsx)(n.em,{children:"Quanteninformation"}),", die sich bereits in der Entwicklung befand.\nDas Feld der ",(0,t.jsx)(n.em,{children:"Quanteninformation und -berechnung"})," wurde geboren.\nEs hat sich seitdem zu einem reichen, multidisziplin\xe4ren Forschungsgebiet entwickelt, und zahlreiche Vorteile von Quanten- gegen\xfcber klassischer Information und Berechnung wurden in einer Vielzahl von ",(0,t.jsx)(n.em,{children:"theoretischen"})," Bereichen der Kommunikation, Berechnung und Kryptographie identifiziert."]}),"\n",(0,t.jsx)(n.h3,{id:"quantum-computing-in-practice",children:"Quantencomputing in der Praxis"}),"\n",(0,t.jsx)(n.p,{children:"In praktischer Hinsicht werden zwei Dinge ben\xf6tigt, um diese Art von theoretischen Vorteilen in reale Vorteile umzusetzen: die Ger\xe4te selbst und die Methoden, um ihr Potenzial zu erschlie\xdfen."}),"\n",(0,t.jsx)(n.p,{children:"Im Gegensatz zu klassischen Computern tr\xe4gt niemand einen Quantencomputer in der Hosentasche.\nBis vor Kurzem, wenn du mit einem Quantencomputer experimentieren wolltest, musstest du einen selbst bauen und warten\n(normalerweise in einem tr\xfcben Universit\xe4tskellerlabor), und du h\xe4ttest bestenfalls ein paar sehr verrauschte Qubits.\nDas ist nicht mehr der Fall.\nIm Jahr 2016 stellte IBM Quantum\xae den ersten Quantenprozessor in der Cloud zur Verf\xfcgung.\nEr hatte nur 5 Qubits und relativ hohe Fehlerraten, aber wir haben seitdem einen langen Weg zur\xfcckgelegt."}),"\n",(0,t.jsx)(n.p,{children:"Neben dem Bau von Quantencomputern m\xfcssen wir auch Methoden entwickeln, um sie effektiv einzusetzen.\nW\xe4hrend theoretische Fortschritte in Quantenalgorithmen und -protokollen ein starkes Potenzial andeuten, liegt die Herausforderung, praktische Verwendungen f\xfcr das Quantencomputing zu finden, noch vor uns.\nDie heutigen Quantencomputer k\xf6nnen noch keine fehlertoleranten Berechnungen durchf\xfchren, die erforderlich w\xe4ren, um bekannte theoretische Vorteile in praktische Vorteile umzusetzen.\nAber sie liegen jenseits des Erreichbaren f\xfcr klassische Computersimulationen, und wir k\xf6nnen darauf abzielen, diese Tatsache f\xfcr Rechenleistung zu nutzen."}),"\n",(0,t.jsx)(n.p,{children:"Mit diesen Fortschritten haben wir ein neues Werkzeug f\xfcr die Berechnung, und es liegt an uns, herauszufinden, was wir damit anfangen k\xf6nnen."}),"\n",(0,t.jsx)(n.h3,{id:"potential-applications",children:"Potenzielle Anwendungen"}),"\n",(0,t.jsx)(n.p,{children:"Es wird nicht erwartet, dass Quantencomputing n\xfctzlich sein wird, um zu untersuchen, wie Autos im Wind abschneiden.\nAber es gibt andere physikalische Prozesse \u2013 wie solche, die beim Design von Batterien oder bei bestimmten chemischen Reaktionen beteiligt sind \u2013, bei denen die F\xe4higkeit eines Quantencomputers, die Natur zu emulieren, zu einem Quantum Advantage f\xfchren k\xf6nnte.\nAllgemeiner gesagt gibt es viele Probleme, die selbst f\xfcr modernste Supercomputer zu schwierig oder kostspielig sind, darunter Probleme, die f\xfcr unsere Gesellschaft sehr relevant sind.\nQuantencomputing bietet m\xf6glicherweise nicht f\xfcr alle L\xf6sungen an, aber f\xfcr einige k\xf6nnte es welche anbieten."}),"\n",(0,t.jsx)(n.p,{children:"Die folgenden drei Anwendungsbereiche stellen Ziele im Bereich des verrauschten Quantencomputings dar, vor der Implementierung von Quantenfehlerkorrektur und Fehlertoleranz."}),"\n",(0,t.jsxs)(n.ul,{children:["\n",(0,t.jsx)(n.li,{children:"Optimierung"}),"\n",(0,t.jsx)(n.li,{children:"Natursimulation"}),"\n",(0,t.jsx)(n.li,{children:"Struktur in Daten finden (einschlie\xdflich maschinelles Lernen)"}),"\n"]}),"\n",(0,t.jsx)(n.p,{children:"Wir werden diese Themen sp\xe4ter im Kurs ausf\xfchrlicher besprechen."}),"\n",(0,t.jsx)(n.h3,{id:"state-of-the-technology",children:"Stand der Technik"}),"\n",(0,t.jsx)(n.p,{children:"Der Bau von Quantencomputern ist eine schwierige technologische Herausforderung, und es sind erst 8 Jahre vergangen, seit kleine Quantencomputer \xf6ffentlich zug\xe4nglich sind.\nIn diesen 8 Jahren haben wir auf vielen Fronten Fortschritte erzielt."}),"\n",(0,t.jsxs)(n.p,{children:["Zahlreiche IBM-Quantenprozessoren sind nun \xfcber die Cloud zug\xe4nglich, von denen alle mehr als 100 Qubits haben.\nAber es ist nicht nur die Gr\xf6\xdfe der Prozessoren, die wichtig ist \u2013 das ist nur eine Metrik, die uns interessiert.\nDie Gate-Qualit\xe4t hat sich ebenfalls dramatisch verbessert, und wir haben auch Methoden eingef\xfchrt, um Fehler zu reduzieren und zu mindern, die quantenmechanischen Systemen innewohnen, selbst wenn wir auf die Schaffung fehlertoleranter Systeme hinarbeiten.\nDrei grundlegende Metriken \u2013 ",(0,t.jsx)(n.em,{children:"Gr\xf6\xdfe"}),", ",(0,t.jsx)(n.em,{children:"Qualit\xe4t"})," und ",(0,t.jsx)(n.em,{children:"Geschwindigkeit"})," \u2013 sind entscheidend f\xfcr die Verfolgung von Leistungsverbesserungen."]}),"\n",(0,t.jsxs)(n.ul,{children:["\n",(0,t.jsxs)(n.li,{children:["\n",(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.strong,{children:"Gr\xf6\xdfe."})," Mehr Qubits sind offensichtlich besser, aber nur wenn die Erh\xf6hung der Anzahl die Leistung nicht beeintr\xe4chtigt\n(was der Fall sein kann). Tats\xe4chlich wollen wir mehr qualitativ hochwertige Qubits, die nicht durch \xdcbersprechen miteinander\ninterferieren, wenn wir das nicht wollen. Die Art und Weise, wie die Qubits miteinander verbunden sind, ist ebenfalls wichtig, und\ndie Herausforderung, wie man das am besten macht, stellt eine Herausforderung f\xfcr supraleitende Qubit-Schaltungen dar."]}),"\n"]}),"\n",(0,t.jsxs)(n.li,{children:["\n",(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.strong,{children:"Qualit\xe4t."})," Eine weitere wichtige Metrik, die wir beobachten, um Leistungsverbesserungen im Laufe der Zeit zu verfolgen, ist die\nFidelit\xe4t von 2-Qubit-Gates. Gates, die auf einzelnen Qubits laufen, sind nicht so fehleranf\xe4llig wie 2-Qubit-Gates, die daher\ndas gr\xf6\xdfere Anliegen sind. (2-Qubit-Gates sind auch entscheidend, weil sie f\xfcr die Erzeugung von Verschr\xe4nkung zwischen den Qubits\nverantwortlich sind, von der man annimmt, dass sie eines der physikalischen Ph\xe4nomene ist, das Quantencomputing seine Leistung verleiht.)"]}),"\n"]}),"\n",(0,t.jsxs)(n.li,{children:["\n",(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.strong,{children:"Geschwindigkeit."})," Zuletzt geht es um Geschwindigkeit und Effizienz. Kurz gesagt sollte die f\xfcr die Ausf\xfchrung eines Programms\naufgewendete Zeit (einschlie\xdflich sowohl quantenmechanischer als auch klassischer Teile) so kurz wie m\xf6glich sein."]}),"\n"]}),"\n"]}),"\n",(0,t.jsx)(n.h2,{id:"conclusion",children:"Fazit"}),"\n",(0,t.jsx)(n.p,{children:"Es ist wirklich eine aufregende Zeit, im Bereich des Quantencomputings zu arbeiten: Zum ersten Mal in der Geschichte k\xf6nnen wir beginnen, einen Rechenbereich zu erkunden, der jenseits des klassischen Computings liegt."}),"\n",(0,t.jsx)(n.p,{children:"T.J. Watson hat einmal ber\xfchmt vorhergesagt, es g\xe4be einen Weltmarkt f\xfcr nur wenige Computer.\nWir m\xf6gen jetzt dar\xfcber lachen, wie weit er daneben lag \u2013 aber dabei m\xfcssen wir anerkennen, dass wir den Vorteil der R\xfcckschau haben.\nUnd wir sollten auch anerkennen, dass wir Menschen dazu neigen, das Potenzial zuk\xfcnftiger Technologien grob zu untersch\xe4tzen.\nJetzt, da wir an der Reihe sind und Rollen als fr\xfche Pioniere des Quantencomputings einnehmen, sollten wir das im Hinterkopf behalten."}),"\n",(0,t.jsx)(n.p,{children:"Quantencomputing wird oft dem klassischen Computing als etwas klar Unterschiedliches und in Konkurrenz dazu gegen\xfcbergestellt.\nAber aus einer breiteren Perspektive k\xf6nnen wir Quantencomputing einfach als ein weiteres Kapitel in einer langen Geschichte sehen.\nEs liegt in unserer Natur als Menschen, neue Wege des Rechnens zu suchen und die Kraft zu nutzen, die uns die nat\xfcrliche Welt daf\xfcr bietet.\nDas tun wir seit Jahrhunderten.\nQuantencomputing bietet uns ein neues Werkzeug in diesem Bestreben, und es liegt an uns, zu entdecken, wie wir die Leistung nutzen k\xf6nnen, die es uns bietet."})]})}function l(e={}){const{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,t.jsx)(n,{...e,children:(0,t.jsx)(c,{...e})}):c(e)}},28453(e,n,i){i.d(n,{R:()=>u,x:()=>a});var r=i(96540);const t={},s=r.createContext(t);function u(e){const n=r.useContext(s);return r.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function a(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(t):e.components||t:u(e.components),r.createElement(s.Provider,{value:n},e.children)}}}]);